// `mbgl::util::source_location` provides the interface of `std::source_location`
// on platforms whose standard library does not ship it yet (e.g. OpenHarmony),
// without the undefined behavior of adding declarations to namespace `std`.
//
// When the standard library type is available, this is simply an alias for it.
// Otherwise, a compatible fallback is provided, built on compiler intrinsics
// when available and on the standard `__FILE__`/`__func__`/`__LINE__`
// primitives as a last resort.
//
// Use `MLN_SOURCE_LOCATION_CURRENT()` to capture the current location; it
// works with either implementation.

#if defined(__cpp_lib_source_location) && __cpp_lib_source_location >= 201907L

namespace mbgl {
namespace util {

using source_location = std::source_location;

} // namespace util
} // namespace mbgl

#define MLN_SOURCE_LOCATION_CURRENT() ::mbgl::util::source_location::current()

#else

#if !defined(MLN_UTIL_HAS_LOCATION_BUILTINS)
#if defined(__has_builtin)
#if __has_builtin(__builtin_FILE) && __has_builtin(__builtin_LINE) && __has_builtin(__builtin_FUNCTION)
#define MLN_UTIL_HAS_LOCATION_BUILTINS 1
#endif
#endif
#endif

#if !defined(MLN_UTIL_HAS_LOCATION_BUILTINS)
#if defined(__GNUC__) && !defined(__clang__)
// GCC has provided __builtin_FILE/__builtin_LINE/__builtin_FUNCTION since 4.8,
// but only defines __has_builtin from version 10.
#define MLN_UTIL_HAS_LOCATION_BUILTINS 1
#endif
#endif

namespace mbgl {
namespace util {

class source_location {
public:
#if MLN_UTIL_HAS_LOCATION_BUILTINS
    static constexpr source_location current(const char* file = __builtin_FILE(),
                                             const char* function = __builtin_FUNCTION(),
                                             std::uint_least32_t line = __builtin_LINE(),
                                             std::uint_least32_t column = 0) noexcept {
        return source_location(file, function, line, column);
    }
#endif

    constexpr source_location(const char* file,
                              const char* function,
                              std::uint_least32_t line,
                              std::uint_least32_t column = 0) noexcept
        : fileName(file),
          functionName(function),
          lineNumber(line),
          columnNumber(column) {}

    constexpr std::uint_least32_t line() const noexcept { return lineNumber; }
    constexpr std::uint_least32_t column() const noexcept { return columnNumber; }
    constexpr const char* file_name() const noexcept { return fileName; }
    constexpr const char* function_name() const noexcept { return functionName; }

private:
    const char* fileName;
    const char* functionName;
    std::uint_least32_t lineNumber;
    std::uint_least32_t columnNumber;
};

} // namespace util
} // namespace mbgl

#if MLN_UTIL_HAS_LOCATION_BUILTINS
#define MLN_SOURCE_LOCATION_CURRENT() ::mbgl::util::source_location::current()
#else
